#include <bits/stdc++.h>
#define int long long
using namespace std;
int n , m;
int dis[ 105 ][ 105 ];
int ans = INT_MAX;
signed main() {
	cin >> n >> m;
	memset( dis , 0x3f , sizeof( dis ) );
	for( int i = 1 ; i <= n ; i++ ) {
		dis[ i ][ i ] = 0;
	}
	for( int i = 1 ; i <= m ; i++ ) {
	    int u , v , w;
	    cin >> u >> v >> w;
	    dis[ u ][ v ] = dis[ v ][ u ] = w;
	}
	for( int k = 1 ; k <= n ; k++ ) {
		for( int i = 1 ; i <= n ; i++ ) {
			for( int j = 1 ; j <= n ; j++ ) {
				dis[ i ][ j ] = min( dis[ i ][ j ] , dis[ i ][ k ] + dis[ k ][ j ] );
			}
		}
	}
	for( int u = 1 ; u <= n ; u++ ) {
		for( int v = 1 ; v <= n ; v++ ) {
			int dis2[ 105 ][ 105 ];
			memset( dis2 , 0x3f , sizeof( dis2 ) );
			for( int i = 1 ; i <= n ; i++ ) {
				dis2[ i ][ i ] = 0;
			}
			for( int i = 1 ; i <= n ; i++ ) {
				for( int j = 1 ; j <= n ; j++ ) {
					dis2[ i ][ j ] = dis[ i ][ j ];
				}
			}
			dis2[ u ][ v ] = dis2[ v ][ u ] = 0;
			for( int i = 1 ; i <= n ; i++ ) {
				for( int j = 1 ; j <= n ; j++ ) {
					dis2[ i ][ j ] = min( dis2[ i ][ j ] , dis2[ i ][ u ] + dis2[ v ][ j ] );
				}
			}
			for( int i = 1 ; i <= n ; i++ ) {
				for( int j = 1 ; j <= n ; j++ ) {
					dis2[ i ][ j ] = min( dis2[ i ][ j ] , dis2[ i ][ v ] + dis2[ u ][ j ] );
				}
			}
			int s = 0;
			for( int i = 1 ; i <= n ; i++ ) {
				for( int j = 1 ; j <= n ; j++ ) {
					s += dis2[ i ][ j ];
				}
			}
			ans = min( ans , s );
		}
	}
	cout << ans / 2;
	return 0;
}
